
// ─── LAUNCH SITES ─────────────────────────────
const LAUNCH_SITES=[
  {region:'North America',sites:[
    {name:'Kennedy Space Center', short:'KSC',  country:'USA',        lat:28.5, lon:-80.6,  azMin:37,  azMax:112,
     note:'Cape Canaveral. Primary US launch site.',
     desc:'NASA\'s primary crewed launch complex since 1968. Home to Apollo, Skylab, and the Space Shuttle. LC-39A and 39B now host Falcon 9, Falcon Heavy, and SLS. Apollo 11 — the first crewed Moon landing — departed from LC-39A in July 1969. The site has supported over 200 orbital launches and remains the symbolic heart of American human spaceflight.'},
    {name:'Vandenberg SFB',       short:'VAFB', country:'USA',        lat:34.6, lon:-120.6, azMin:147, azMax:201,
     note:'Polar & sun-sync. Retrograde only from here.',
     desc:'Established as Camp Cooke in 1941, converted to a missile test center in 1956. The US Air Force\'s premier site for polar and sun-synchronous orbits — the only US site that can reach high inclinations without overflying populated areas. First space launch was Discoverer 1 in 1959. Routinely handles classified NRO reconnaissance and NOAA weather satellites. SpaceX operates two pads here for Falcon 9 and Falcon Heavy.'},
    {name:'Wallops Island',       short:'WLPS', country:'USA',        lat:37.8, lon:-75.5,  azMin:90,  azMax:159,
     note:'MARS. Mid-inclination and polar capable.',
     desc:'One of the oldest launch facilities in the world, opened in 1945 as an NACA rocket test range. Now NASA\'s Wallops Flight Facility, home to the Mid-Atlantic Regional Spaceport (MARS). Primarily supports sounding rockets and small orbital vehicles. Northrop Grumman\'s Antares rocket launches Cygnus ISS resupply missions from Pad 0A. The site\'s mid-latitude location suits ISS-inclination and sun-synchronous missions.'},
    {name:'Kodiak / PSCA',        short:'KDK',  country:'USA',        lat:57.4, lon:-152.3, azMin:110, azMax:220,
     note:'Alaska. High-inclination and polar.',
     desc:'Pacific Spaceport Complex – Alaska, opened 1998 on Kodiak Island. Operated by the Alaska Aerospace Corporation, it is one of very few commercial orbital launch sites in the US. The high latitude and open ocean range make it ideal for polar and high-inclination orbits with minimal range safety constraints. Astra used the site for early Rocket 3 attempts. Now hosts multiple small-launch-vehicle providers.'},
  ]},
  {region:'Russia',sites:[
    {name:'Baikonur Cosmodrome',  short:'BKR',  country:'Russia',     lat:45.9, lon:63.3,   azMin:51,  azMax:100, minInc:51.6,
     note:'Range safety forces min inc ≈ 51.6° despite 45.9° latitude.',
     desc:'The world\'s first and largest operational launch facility, built in 1955 in what is now Kazakhstan. Yuri Gagarin lifted off from Site No. 1 — "Gagarin\'s Start" — on April 12, 1961, becoming the first human in space. Sputnik, Luna, Venera, and every Soviet crewed mission launched from here. Russia leases the complex from Kazakhstan. Soyuz crewed ISS flights departed from Baikonur until Vostochny assumed some missions. The site\'s range safety corridor forces a minimum inclination of ~51.6° regardless of latitude.'},
    {name:'Plesetsk Cosmodrome',  short:'PLSK', country:'Russia',     lat:62.8, lon:40.7,   azMin:66,  azMax:160,
     note:'Primary Russian military site. Polar capable.',
     desc:'Russia\'s primary military launch complex, opened 1957 as an ICBM base and converted to space launches in 1966. By sheer launch count, Plesetsk is the most-used orbital launch site in history, having supported over 1,500 missions. Its high latitude makes it naturally suited to polar and retrograde orbits needed for reconnaissance satellites. Primarily serves Soyuz-2 and Rokot. Angara test flights have also launched from Plesetsk.'},
    {name:'Vostochny Cosmodrome', short:'VST',  country:'Russia',     lat:51.9, lon:128.3,  azMin:60,  azMax:120,
     note:'New Russian civilian site.',
     desc:'Russia\'s newest launch complex, constructed in the Amur Oblast on Russian sovereign territory to reduce dependence on leased Baikonur. First orbital launch was a Soyuz-2.1a in April 2016. Development has been plagued by funding scandals and contractor fraud. The site is planned to eventually host Angara-A5 heavy-lift vehicles and support crewed missions, freeing Russia from its Baikonur lease obligations.'},
  ]},
  {region:'Europe / Americas',sites:[
    {name:'Kourou (CSG)',         short:'CSG',  country:'France/ESA', lat:5.2,  lon:-52.6,  azMin:10,  azMax:95,
     note:'Near-equatorial. Ariane advantage: GTO inc ≈ 5.2°.',
     desc:'The Guiana Space Centre, operated jointly by ESA and CNES since 1968. Its near-equatorial location in French Guiana is a strategic advantage — Earth\'s rotational velocity contributes ~460 m/s to eastward launches, and GTO payloads arrive at just 5.2° inclination, minimising the apogee kick needed for geostationary orbit. Ariane 5 completed over 110 consecutive successful missions here. The ELA-4 complex now hosts Ariane 6, which began commercial operations in 2024.'},
    {name:'Alcântara (ALZ)',      short:'ALZ',  country:'Brazil',     lat:-2.3, lon:-44.4,  azMin:10,  azMax:180,
     note:'Near-equatorial. Southern hemisphere.',
     desc:'Brazil\'s Alcântara Launch Center near São Luís, Maranhão. Operational since 1990 for sounding rockets. Its near-equatorial location — just 2.3° south — offers exceptional launch performance, arguably the best of any orbital site in the world by latitude alone. A 2003 attempt to launch the VLS-1 rocket ended in tragedy when the vehicle exploded on the pad during pre-launch checks, killing 21 technicians. A US–Brazil Technology Safeguards Agreement signed in 2019 opened the site to American commercial launch providers.'},
  ]},
  {region:'Asia / Pacific',sites:[
    {name:'Tanegashima',          short:'TNGS', country:'Japan',      lat:30.4, lon:130.9,  azMin:90,  azMax:115,
     note:'JAXA primary launch site.',
     desc:'JAXA\'s primary launch complex on the southern tip of Tanegashima Island. Japan\'s space launch history dates to 1970, when a Lambda-4S rocket made it the fourth nation to orbit a satellite. The site now hosts H-IIA, H-IIB, and the next-generation H3 vehicle. Unusually, launch windows are constrained by bilateral agreements with local fishing cooperatives, restricting launches to two short windows per year. H-IIA has achieved a 97%+ success rate over 40+ missions.'},
    {name:'Jiuquan (JSLC)',       short:'JSLC', country:'China',      lat:40.6, lon:100.3,  azMin:57,  azMax:100,
     note:'Chinese crewed launches.',
     desc:'China\'s oldest and most storied launch site, built in 1958 in the Gobi Desert of Inner Mongolia. The first Chinese satellite, Dong Fang Hong 1, launched from here in 1970, making China the fifth nation to reach orbit independently. Every Chinese crewed Shenzhou mission — including Yang Liwei\'s pioneering 2003 flight — has launched from Jiuquan. The site also hosts Long March 2F, the only Chinese rocket certified for human spaceflight.'},
    {name:'Xichang (XSLC)',       short:'XSLC', country:'China',      lat:28.2, lon:102.0,  azMin:90,  azMax:115,
     note:'Chinese GTO launches.',
     desc:'Xichang Satellite Launch Center in Sichuan Province, operational since 1984. China\'s dedicated GTO launch facility, positioned at 1,825 m altitude which provides a small atmospheric performance benefit. The entire Beidou navigation satellite constellation was launched from Xichang. Chang\'e lunar probes, including the historic Chang\'e-4 mission to the lunar far side, also departed from here. The site\'s mountainous setting makes stage recovery impossible, limiting it to expendable operations.'},
    {name:'Wenchang (WSLC)',      short:'WSLC', country:'China',      lat:19.6, lon:110.9,  azMin:90,  azMax:115,
     note:'Newest Chinese site. Lower latitude.',
     desc:'China\'s newest and lowest-latitude orbital facility, opened in 2016 on Hainan Island. Designed specifically for the Long March 5 and 7 heavy-lift vehicles. The CZ-5B that delivered the Tianhe core module of China\'s space station launched from here, as did Chang\'e-5, which returned the first lunar samples since 1976. The coastal location allows spent stages to fall safely into the South China Sea and enables sea transport of large rocket stages.'},
    {name:'Sriharikota (SHAR)',   short:'SHAR', country:'India',      lat:13.7, lon:80.2,   azMin:50,  azMax:140,
     note:'ISRO primary launch site.',
     desc:'Satish Dhawan Space Centre on Sriharikota Island, Andhra Pradesh. India\'s only operational orbital launch facility, active since 1971. ISRO\'s PSLV — one of the world\'s most reliable small-to-medium launchers — has launched over 50 missions from here with a near-perfect record. The site hosted Chandrayaan-1 (2008), India\'s first lunar mission, and Mangalyaan (2013), which reached Mars on the first attempt. The new Second Launch Pad supports GSLV and LVM3 heavy-lift missions.'},
    {name:'Mahia Peninsula',      short:'MHI',  country:'New Zealand',lat:-39.3,lon:177.9,  azMin:57,  azMax:185,
     note:'Rocket Lab. Southern hemisphere. ~39° min inc.',
     desc:'Rocket Lab\'s private orbital spaceport on the Mahia Peninsula, New Zealand — the world\'s first licensed private orbital launch site. The first Electron launch attempt was in May 2017, with the first successful orbital mission in January 2018. The remote location and dedicated range allow rapid launch cadence without conflict with other users. The southern hemisphere position is advantageous for direct sun-synchronous insertion. Rocket Lab has achieved over 50 Electron launches and is developing the larger Neutron vehicle.'},
  ]},
];

