let _mapHov=null;
let _mapDrag=false;
let _mapDragPos=null;

function drawSiteMap(){
  const canvas=document.getElementById('site-map');
  if(!canvas||!canvas._smInited)return;
  const dpr=canvas._dpr||1;
  const ctx=canvas.getContext('2d');
  // Work in CSS-pixel space — scale once, no dpr multiplication needed anywhere else
  const W=canvas.width/dpr, H=canvas.height/dpr;
  ctx.save();
  ctx.scale(dpr,dpr);

  const cs=getComputedStyle(document.documentElement);
  const accent=cs.getPropertyValue('--accent').trim();
  const panelCol=cs.getPropertyValue('--panel').trim();
  const proj=(lon,lat)=>[(lon+180)/360*W,(90-lat)/180*H];

  // Ocean
  ctx.fillStyle=panelCol;
  ctx.fillRect(0,0,W,H);

  // Graticules
  ctx.setLineDash([3,6]);ctx.lineWidth=0.5;
  ctx.strokeStyle='rgba(255,255,255,0.07)';
  for(const lat of [-66.5,-23.5,0,23.5,66.5]){
    const[,y]=proj(0,lat);ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();
  }
  const[mx]=proj(0,0);ctx.beginPath();ctx.moveTo(mx,0);ctx.lineTo(mx,H);ctx.stroke();
  ctx.setLineDash([]);

  // Land — accent fill + accent outline
  LAND_POLYS.forEach(poly=>{
    ctx.beginPath();
    poly.forEach(([lon,lat],i)=>{const[x,y]=proj(lon,lat);i?ctx.lineTo(x,y):ctx.moveTo(x,y);});
    ctx.closePath();
    ctx.fillStyle=accent+'28';ctx.fill();
    ctx.strokeStyle=accent;ctx.lineWidth=0.75;ctx.stroke();
  });

  // Site dots — built-in + user spaceports
  const allSites=[
    ...LAUNCH_SITES.flatMap(r=>r.sites).map(s=>({...s,_key:s.short})),
    ...userSpaceports.filter(s=>s.lon!=null).map(s=>({...s,_key:'usp_'+s._uid,_user:true}))
  ];
  allSites.forEach(site=>{
    if(site.lon==null)return;
    const active=activeSiteKey===site._key;
    const drawLon=active&&_mapDrag&&_mapDragPos?_mapDragPos.lon:site.lon;
    const drawLat=active&&_mapDrag&&_mapDragPos?_mapDragPos.lat:site.lat;
    const[x,y]=proj(drawLon,drawLat);
    if(active&&_mapDrag){
      // ghost ring at original position
      const[ox,oy]=proj(site.lon,site.lat);
      ctx.beginPath();ctx.arc(ox,oy,5,0,Math.PI*2);
      ctx.strokeStyle=accent+'55';ctx.lineWidth=1;ctx.setLineDash([3,3]);ctx.stroke();
      ctx.setLineDash([]);
    }
    ctx.beginPath();ctx.arc(x,y,active?5:3,0,Math.PI*2);
    ctx.fillStyle=active?accent:'rgba(220,220,220,0.75)';ctx.fill();
    if(site._user&&!active){
      ctx.beginPath();ctx.arc(x,y,3,0,Math.PI*2);
      ctx.strokeStyle=accent;ctx.lineWidth=1;ctx.stroke();
    }
    if(active){
      ctx.font='bold 11px JetBrains Mono,monospace';
      ctx.fillStyle=accent;ctx.fillText(site.short,x+7,y+4);
    }
  });

  // Hover crosshair + tooltip — only when map is fully expanded
  if(_mapHov && canvas.offsetWidth > 200){
    const[x,y]=proj(_mapHov.lon,_mapHov.lat);
    ctx.setLineDash([2,3]);ctx.lineWidth=0.5;ctx.strokeStyle='rgba(255,255,255,0.3)';
    ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();
    ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(W,y);ctx.stroke();
    ctx.setLineDash([]);
    ctx.beginPath();ctx.arc(x,y,3.5,0,Math.PI*2);
    ctx.fillStyle='rgba(255,255,255,0.85)';ctx.fill();
    const latS=Math.abs(_mapHov.lat).toFixed(1)+(_mapHov.lat>=0?'°N':'°S');
    const lonS=Math.abs(_mapHov.lon).toFixed(1)+(_mapHov.lon>=0?'°E':'°W');
    const label=latS+' '+lonS;
    ctx.font='11px JetBrains Mono,monospace';
    const lw=ctx.measureText(label).width+8;
    const lx=x+10+lw>W?x-lw-6:x+10;
    const ly=y>H*0.78?y-7:y+14;
    ctx.fillStyle='rgba(0,0,0,0.72)';ctx.fillRect(lx-3,ly-11,lw,15);
    ctx.fillStyle='rgba(255,255,255,0.9)';ctx.fillText(label,lx,ly);
  }

  ctx.restore();
}

function initSiteMap(){
  const canvas=document.getElementById('site-map');
  if(!canvas||canvas._smInited)return;
  canvas._smInited=true;
  function _smResize(){
    clearTimeout(canvas._szTimer);
    canvas._szTimer=setTimeout(()=>{
      const dpr=window.devicePixelRatio||1;
      const w=canvas.offsetWidth,h=canvas.offsetHeight;
      if(!w||!h)return;
      canvas._dpr=dpr;
      canvas.width=Math.round(w*dpr);
      canvas.height=Math.round(h*dpr);
      drawSiteMap();
    },120);
  }
  new ResizeObserver(_smResize).observe(canvas);
  // helpers reused across handlers
  const _smProj=(r,e)=>{
    const W=r.width,H=r.height;
    const lon=((e.clientX-r.left)/W)*360-180;
    const lat=90-((e.clientY-r.top)/H)*180;
    return{lon,lat};
  };
  const _smActiveDotPos=()=>{
    const site=getCurrentSite();
    if(!site||site.lon==null)return null;
    return{lon:site.lon,lat:site.lat};
  };
  const _smNearActive=(cx,cy,r)=>{
    const pos=_smActiveDotPos();
    if(!pos)return false;
    const W=r.width,H=r.height;
    const sx=(pos.lon+180)/360*W, sy=(90-pos.lat)/180*H;
    return Math.hypot(cx-sx,cy-sy)<10;
  };

  canvas.addEventListener('mousedown',e=>{
    if(!activeSiteKey)return;
    const r=canvas.getBoundingClientRect();
    if(_smNearActive(e.clientX-r.left,e.clientY-r.top,r)){
      _mapDrag=true;_mapDragPos=_smProj(r,e);
      e.preventDefault();
    }
  });
  canvas.addEventListener('mousemove',e=>{
    const r=canvas.getBoundingClientRect();
    const pos=_smProj(r,e);
    _mapHov=pos;
    if(_mapDrag){
      _mapDragPos=pos;
      document.getElementById('site-lat').value=pos.lat.toFixed(2);
      canvas.style.cursor='grabbing';
    } else {
      canvas.style.cursor=_smNearActive(e.clientX-r.left,e.clientY-r.top,r)&&activeSiteKey
        ?'grab':'crosshair';
    }
    drawSiteMap();
  });
  canvas.addEventListener('mouseup',e=>{
    if(!_mapDrag)return;
    _mapDrag=false;
    const r=canvas.getBoundingClientRect();
    const{lon,lat}=_smProj(r,e);
    document.getElementById('site-lat').value=lat.toFixed(2);
    // Persist if user spaceport
    if(activeSiteKey&&activeSiteKey.startsWith('usp_')){
      const uid=parseInt(activeSiteKey.slice(4));
      const sp=userSpaceports.find(s=>s._uid===uid);
      if(sp){sp.lat=parseFloat(lat.toFixed(4));sp.lon=parseFloat(lon.toFixed(4));persistUserSpaceports();}
    }
    _mapDragPos=null;
    canvas.style.cursor='crosshair';
    drawSiteMap();
  });
  canvas.addEventListener('mouseleave',()=>{
    if(_mapDrag){_mapDrag=false;_mapDragPos=null;}
    _mapHov=null;
    canvas.style.cursor='crosshair';
    drawSiteMap();
  });
  canvas.addEventListener('click',e=>{
    if(_mapDragPos!==null)return; // suppress click after drag commit
    const r=canvas.getBoundingClientRect();
    const cx=e.clientX-r.left,cy=e.clientY-r.top;
    const W=r.width,H=r.height;
    const proj=(lon,lat)=>[(lon+180)/360*W,(90-lat)/180*H];
    // Snap to nearest built-in or user site within 15px
    let best=null,bestD=15,bestKey=null;
    LAUNCH_SITES.flatMap(g=>g.sites).forEach(s=>{
      if(s.lon==null)return;
      const[sx,sy]=proj(s.lon,s.lat);
      const d=Math.hypot(cx-sx,cy-sy);
      if(d<bestD){bestD=d;best=s;bestKey=null;}
    });
    userSpaceports.forEach(sp=>{
      if(sp.lon==null)return;
      const[sx,sy]=proj(sp.lon,sp.lat);
      const d=Math.hypot(cx-sx,cy-sy);
      if(d<bestD){bestD=d;best=sp;bestKey='usp_'+sp._uid;}
    });
    if(best){
      if(bestKey){
        activeSiteKey=bestKey;
        document.getElementById('site-lat').value=best.lat;
        document.getElementById('az-min').value=best.azMin;
        document.getElementById('az-max').value=best.azMax;
        buildSiteSelector();updateSiteNotes(best);updateIncForSite(best);
      } else {loadSite(best);}
      return;
    }
    const lat=90-(cy/H)*180;
    document.getElementById('site-lat').value=lat.toFixed(1);
    activeSiteKey=null;
    document.getElementById('site-note').textContent='';
    document.getElementById('inc-tracked-note').style.display='none';
    const descEl=document.getElementById('site-desc');
    if(descEl){descEl.textContent='';descEl.style.display='none';}
    buildSiteSelector();
  });
  _smResize();
}

